import{_ as n}from"./chunks/Vulnerability-Disclosure-Jedox-Jedox-04-2023.CIQ4NkLw.js";import{_ as r,o as i,c as t,an as a}from"./chunks/framework.D5fFzH9V.js";const f=JSON.parse('{"title":"Advisories","description":"Security Advisories und Disclosure-Berichte von Syslifters.","frontmatter":{"description":"Security Advisories und Disclosure-Berichte von Syslifters."},"headers":[],"relativePath":"de/advisories.md","filePath":"de/advisories.md"}'),s={name:"de/advisories.md"};function o(d,e,u,l,c,h){return i(),t("div",null,[...e[0]||(e[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /de/advisories.md for this page in Markdown format</div><h1 id="advisories" tabindex="-1">Advisories <a class="header-anchor" href="#advisories" aria-label="Permalink to &quot;Advisories&quot;">​</a></h1><h2 id="jedox-2023" tabindex="-1">Jedox 2023 <a class="header-anchor" href="#jedox-2023" aria-label="Permalink to &quot;Jedox 2023&quot;">​</a></h2><h3 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h3><a href="/assets/vulnerability-disclosure/Vulnerability-Disclosure-Jedox-Jedox-04-2023.pdf" target="_blank" rel="noreferrer"><figure class="on-the-fly-behavior" style="float:right;width:30%;margin:0.5em;"><img alt="Vulnerability Disclosure Jedox Preview" src="'+n+'" style="border:1px solid;"><figcaption>Hier zum Bericht</figcaption></figure></a><ul><li><strong><span class="iconify" data-icon="fa6-solid:computer" aria-hidden="true"></span> Hersteller:</strong> <a href="https://www.jedox.com/de/" target="_blank">Jedox GmbH</a></li><li><strong><span class="iconify" data-icon="fa6-brands:product-hunt" aria-hidden="true"></span> Produkt:</strong> Jedox / Jedox Cloud</li><li><strong><span class="iconify" data-icon="octicon:versions-16" aria-hidden="true"></span> Version:</strong> Jedox 2020.2.5+</li><li><strong><span class="iconify" data-icon="octicon:number-16" aria-hidden="true"></span> CVE Nummer:</strong> CVE-2022-47874, CVE-2022-47875, CVE-2022-47876, CVE-2022-47877, CVE-2022-47878, CVE-2022-47879, CVE-2022-47880</li></ul><h3 id="verlauf" tabindex="-1">Verlauf <a class="header-anchor" href="#verlauf" aria-label="Permalink to &quot;Verlauf&quot;">​</a></h3><ul><li><strong>2022-12-20:</strong> Erstkontakt mit dem Hersteller über zwei Manager</li><li><strong>2022-12-27:</strong> Kontakt mit dem Hersteller über eine öffentliche Mailadresse</li><li><strong>2023-01-11:</strong> Zur Verfügungstellung eines verschlüsselten Kanals durch den Hersteller</li><li><strong>2023-01-18:</strong> Meldung der Schwachstellendetails</li><li><strong>2023-04-28:</strong> Veröffentlichung der Schwachstellendetails</li></ul><h3 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h3><p><strong>CVE-2022-47879: Code Execution über RPC Interfaces</strong><br> Eine Remote Code Execution (RCE) Schwachstelle in <em>/be/rpc.php</em> und <em>/be/erpc.php</em> in Jedox Cloud und Jedox 2020.2.5 erlaubt authentifizierten Benutzern, beliebige PHP-Klassen aus dem Verzeichnis <em>rtn</em> zu laden und deren Methoden auszuführen. Um diese Schwachstelle auszunutzen, benötigt der Angreifer Kenntnis über ladbare Klassen, ihre Methoden und Argumente.</p><p><strong>CVE-2022-47875: Remote Code Execution über Directory Traversal</strong><br> Eine Directory Traversal Schwachstelle in <em>/be/erpc.php</em> in Jedox Cloud und Jedox 2020.2.5 erlaubt authentifizierten Benutzern die Ausführung von beliebigem Code. Um die Schwachstelle auszunutzen, benötigt ein Angreifer Berechtigungen Dateien hochzuladen.</p><p><strong>CVE-2022-47877: Stored Cross-Site Scripting im Log-Modul</strong><br> Eine Stord Cross-Site-Scripting-Schwachstelle in Jedox 2020.2.5 erlaubt es authentifizierten Benutzern, beliebige Skripte oder HTML in die Log-Seite über das Log-Modul einzuschleusen. Um die Schwachstelle auszunutzen, muss der Angreifer eine XSS-Payload an die Protokollnachricht anhängen.</p><p><strong>CVE-2022-47878: Remote Code Execution über konfigurierbaren Storage Path</strong><br> Eine fehlerhafte Eingabevalidierung zur Konfiguration des Storage Paths in Jedox 2020.2.5 erlaubt es authentifizierten Benutzern, den Speicherort als Web-Root-Verzeichnis anzugeben. Nachfolgende Datei-Uploads können zur Ausführung von beliebigem Code führen. Um die Schwachstelle auszunutzen, setzt der Angreifer den Standard-Speicherpfad auf das Web-Root des Webservers.</p><p><strong>CVE-2022-47876: Remote Code Execution über ausführbare Groovy-Scripts</strong><br> Integrator in Jedox 2020.2.5 erlaubt authentifizierten Benutzern, Jobs zu erstellen, um beliebigen Code über Groovy-Skripte auszuführen. Um die Sicherheitslücke auszunutzen, muss der Angreifer in der Lage sein, einen Groovy-Job in Integrator zu erstellen.</p><p><strong>CVE-2022-47874: Offenbarung von Databankzugangsdaten aufgrund unzureichender Zugriffskontrollen</strong><br> Unzureichende Zugriffskontrollen in <em>/tc/rpc</em> in Jedox Cloud und Jedox 2020.2.5 ermöglichen es authentifizierten Benutzern, Details von Datenbankverbindungen über die Klasse <em>com.jedox.etl.mngr.Connections</em> und die Methode <em>getGlobalConnection</em> einzusehen. Um die Sicherheitslücke auszunutzen, muss der Angreifer den Namen der Datenbankverbindung kennen.</p><p><strong>CVE-2022-47880: Offenlegung von Datenbankverbindungen über Verbindungstests</strong><br> Eine Information Disclosure Schwachstelle in <code>/be/rpc.php</code> in Jedox Cloud und Jedox 2020.2.5 ermöglicht es authentifizierten Benutzern mit entsprechenden Berechtigungen, Datenbankverbindungen zu ändern, um die Zugangsdaten über die Funktion <code>test connection</code> offenzulegen. Um die Sicherheitslücke auszunutzen, muss der Angreifer den Host der Datenbankverbindung auf einen unter seiner Kontrolle stehenden Server setzen.</p>',16)])])}const m=r(s,[["render",o]]);export{f as __pageData,m as default};
